    char commit_hash[17];
    minihash((unsigned char *)content, pos, commit_hash);

    char cpath[512];
    snprintf(cpath, sizeof(cpath), ".minigit/commits/%s", commit_hash);
    write_file(cpath, content, pos);
    free(content);

    write_str(".minigit/HEAD", commit_hash);
    write_str(".minigit/index", "");

